#include <bits/stdc++.h>
using namespace std;
map<string,int> t;
string s[1003];
int sum;
int main(){
    int n;
    cin>>n;
    for(int i=1;i<=n;i++){
        string op;
        cin>>op;
        if(op=="touch"){
            string name;
            cin>>name;
            if(!t[name])
                s[++sum]=name,t[name]=sum;
        }else if(op=="rm"){
            string name;
            cin>>name;
            if(t[name])
                t[name]=0;
        }else if(op=="ls"){
            for(int i=1;i<=sum;i++)
                if(t[s[i]]==i)
                    cout<<s[i]<<endl;
        }else if(op=="rename"){
            string x,y;
            cin>>x>>y;
            if(t[x] && !t[y]){
                s[t[x]]=y;
                t[y]=t[x];
                t[x]=0;
            }
        }
    }
    return 0;
}
